// Parse the LLM JSON output and merge with lead context.
// $('Generate Outreach').first().json contains the OpenAI response.
// $('Dedup Check').first().json contains the normalized lead.

const llmOutput = $('Generate Outreach').first().json;
const lead = $('Dedup Check').first().json;

// OpenAI node output shape: { message: { content: '...' } }
const rawContent = llmOutput?.message?.content || llmOutput?.text || '';

if (!rawContent) {
  throw new Error('LLM returned empty content — cannot parse outreach');
}

// Strip markdown code fences if present (```json ... ```)
const cleaned = rawContent.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '').trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  throw new Error(`Failed to parse LLM JSON: ${e.message} — raw: ${rawContent.substring(0, 200)}`);
}

if (!parsed.subject || !parsed.body) {
  throw new Error(`LLM output missing required keys. Got: ${Object.keys(parsed).join(', ')}`);
}

return [{
  json: {
    ...lead,
    subject: parsed.subject,
    body: parsed.body,
    outreach_generated: true
  }
}];
